findings.suggestion:
Add at least one more error test: a failing standard provider (for generation/summarization tasks) to verify errors propagate from both tiers. Example:

it('propagates errors from standard provider on generation tasks', async () => {
  const lightweight = createTrackingProvider('lightweight')
  const failingStandard: LlmProvider = {
    async generateText() { throw new Error('Rate limited') },
    async generateStructured() { throw new Error('Rate limited') },
  }
  const router = new ModelRouter({ providers: { lightweight, standard: failingStandard } })
  await expect(router.generateText({ system: 'Generate report', prompt: 'data' })).rejects.toThrow('Rate limited')
})

